def main():
    data = json.loads(DATA_PATH.read_text(encoding="utf-8-sig"))
    analysis = next(item for item in data["analysis"] if int(item["year"]) == 111)
    for question in analysis["questions"]:
        no = int(question["no"])
        if no in SOLUTIONS:
            question["solution"] = SOLUTIONS[no]
            question["commonMistakes"] = "常見錯誤：未先辨認物理模型；計算題少列式或漏單位；概念題只看關鍵字而未檢查方向、量綱、守恆關係與適用條件。"
            question["keyConcept"] = "關鍵觀念：以牛頓運動、能量守恆、氣體動力論、電磁感應、光量子、繞射與實驗不確定度等基本關係，逐項驗證選項。"
    DATA_PATH.write_text(
        "\ufeff" + json.dumps(data, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )


if __name__ == "__main__":
    main()
